import { useEffect, useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function AdminDashboard() {
  const [stats, setStats] = useState({ totalBookings: 0, activeBookings: 0, totalSlots: 0, revenue: 0, totalUsers: 0 });
  const [bookings, setBookings] = useState([]);
  const [pendingOwners, setPendingOwners] = useState([]);
  const [pendingLots, setPendingLots] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("overview"); // overview | approvals
  const navigate = useNavigate();

  const fetchAdminData = async () => {
    try {
      const role = localStorage.getItem("role");
      if (role !== "admin") {
        navigate("/");
        return;
      }

      const [statsRes, bookingsRes, ownersRes, lotsRes] = await Promise.all([
        axios.get("/admin/stats"),
        axios.get("/admin/bookings"),
        axios.get("/admin/owners/pending"),
        axios.get("/admin/lots/pending")
      ]);

      setStats(statsRes.data);
      setBookings(bookingsRes.data);
      setPendingOwners(ownersRes.data);
      setPendingLots(lotsRes.data);
      setLoading(false);
    } catch (err) {
      console.error("Admin Access Error", err);
      navigate("/");
    }
  };

  useEffect(() => {
    fetchAdminData();
  }, [navigate]);

  const handleApproveOwner = async (ownerId, status) => {
      try {
          await axios.put(`/admin/owners/${ownerId}/approve`, { status });
          fetchAdminData();
      } catch (err) {
          alert("Error updating owner status");
      }
  };

  const handleApproveLot = async (lotId, status) => {
      try {
          await axios.put(`/admin/lots/${lotId}/approve`, { status });
          fetchAdminData();
      } catch (err) {
          alert("Error updating lot status");
      }
  };

  if (loading) return <div style={{ textAlign: "center", marginTop: "50px" }}>Loading Admin Dashboard...</div>;

  return (
    <div style={{ animation: "fadeIn 0.5s ease-out" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "32px", borderBottom: "1px solid var(--border-subtle)", paddingBottom: "20px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
              <div style={{ background: "var(--accent-primary)", color: "white", padding: "12px", borderRadius: "12px", display: "flex", alignItems: "center", justifyContent: "center" }}>
                  <i className="fa-solid fa-shield-halved fa-2x"></i>
              </div>
              <div>
                  <h1 style={{ color: "var(--text-primary)", margin: 0, fontSize: "2.5rem", fontWeight: "800" }}>Admin Dashboard</h1>
                  <p style={{ color: "var(--text-secondary)", margin: 0, fontSize: "1.05rem" }}>System overview and management</p>
              </div>
          </div>
          
          <div style={{ display: "flex", background: "var(--bg-secondary)", borderRadius: "var(--radius-sm)", border: "var(--border-subtle)", padding: "4px" }}>
              <button 
                onClick={() => setActiveTab("overview")} 
                style={{ padding: "8px 16px", background: activeTab === "overview" ? "var(--accent-primary)" : "transparent", color: activeTab === "overview" ? "white" : "var(--text-secondary)", border: "none", borderRadius: "var(--radius-sm)", cursor: "pointer", fontWeight: "600", transition: "all 0.2s" }}>
                Overview
              </button>
              <button 
                onClick={() => setActiveTab("approvals")} 
                style={{ padding: "8px 16px", background: activeTab === "approvals" ? "var(--accent-primary)" : "transparent", color: activeTab === "approvals" ? "white" : "var(--text-secondary)", border: "none", borderRadius: "var(--radius-sm)", cursor: "pointer", fontWeight: "600", transition: "all 0.2s", position: "relative" }}>
                Approvals
                {(pendingOwners.length > 0 || pendingLots.length > 0) && (
                    <span style={{ position: "absolute", top: "-5px", right: "-5px", background: "var(--status-danger)", color: "white", fontSize: "0.7rem", padding: "2px 6px", borderRadius: "10px" }}>
                        {pendingOwners.length + pendingLots.length}
                    </span>
                )}
              </button>
          </div>
      </div>

      {activeTab === "overview" && (
          <>
            {/* Stats Grid */}
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: "24px", marginBottom: "40px" }}>
                <StatCard title="Total Users" value={stats.totalUsers} icon="fa-users" color="var(--accent-primary)" />
                <StatCard title="Active Bookings" value={stats.activeBookings} icon="fa-car" color="var(--status-success)" />
                <StatCard title="Total Slots" value={stats.totalSlots} icon="fa-square-parking" color="var(--status-warning)" />
                <StatCard title="Total Revenue" value={`$${stats.revenue || 0}`} icon="fa-sack-dollar" color="var(--status-danger)" />
            </div>

            {/* Bookings Table */}
            <h2 style={{ marginTop: "10px", color: "var(--text-primary)", fontSize: "1.5rem", display: "flex", alignItems: "center", gap: "8px", marginBottom: "16px" }}>
                <i className="fa-solid fa-clock-rotate-left" style={{ color: "var(--text-muted)" }}></i> Recent Bookings
            </h2>
            <div style={{ overflowX: "auto", background: "white", borderRadius: "var(--radius-md)", boxShadow: "0 4px 10px rgba(0,0,0,0.02)", border: "var(--border-subtle)" }}>
                <table style={{ width: "100%", borderCollapse: "collapse" }}>
                <thead>
                    <tr style={{ background: "var(--bg-tertiary)", textAlign: "left" }}>
                    <th style={thStyle}>User</th>
                    <th style={thStyle}>Vehicle</th>
                    <th style={thStyle}>Location</th>
                    <th style={thStyle}>Slot</th>
                    <th style={thStyle}>Time</th>
                    <th style={thStyle}>Status</th>
                    </tr>
                </thead>
                <tbody>
                    {bookings.map(b => (
                    <tr key={b._id} style={{ borderBottom: "1px solid var(--border-subtle)" }}>
                        <td style={tdStyle}>
                        <div style={{ fontWeight: "600" }}>{b.userId?.name || "Unknown"}</div>
                        <div style={{ fontSize: "0.85em", color: "var(--text-muted)" }}>{b.userId?.email}</div>
                        </td>
                        <td style={tdStyle}>{b.vehicleNumber || "N/A"}</td>
                        <td style={tdStyle}>{b.slotId?.parkingLotId?.name || "Unknown"}</td>
                        <td style={tdStyle}>{b.slotId?.slotNumber || "N/A"}</td>
                        <td style={tdStyle}>
                        <div>{new Date(b.startTime).toLocaleDateString()}</div>
                        <div style={{ fontSize: "0.85em", color: "var(--text-muted)" }}>{new Date(b.startTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} - {new Date(b.endTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>
                        </td>
                        <td style={tdStyle}>
                        <span style={{
                            padding: "6px 12px", borderRadius: "20px", fontSize: "0.75rem", fontWeight: "700", display: "inline-block",
                            background: b.status === "Booked" || b.status === "Active" ? "var(--status-success-bg)" : "var(--status-danger-bg)",
                            color: b.status === "Booked" || b.status === "Active" ? "var(--status-success)" : "var(--status-danger)"
                        }}>
                            {b.status.toUpperCase()}
                        </span>
                        </td>
                    </tr>
                    ))}
                </tbody>
                </table>
            </div>
          </>
      )}

      {activeTab === "approvals" && (
          <div style={{ animation: "fadeIn 0.3s ease-in" }}>
              <div className="grid">
                  {/* Pending Owners Column */}
                  <div>
                      <h2 style={{ fontSize: "1.5rem", marginBottom: "16px", display: "flex", alignItems: "center", gap: "8px" }}>
                          <i className="fa-solid fa-user-tie" style={{ color: "var(--accent-primary)" }}></i> Pending Owners
                      </h2>
                      {pendingOwners.length === 0 ? <p style={{ color: "var(--text-muted)" }}>No pending owner applications.</p> : 
                          pendingOwners.map(o => (
                              <div className="card" key={o._id} style={{ marginBottom: "16px" }}>
                                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "12px" }}>
                                      <h3 style={{ margin: 0 }}>{o.businessName}</h3>
                                  </div>
                                  <div style={{ flexGrow: 1, marginBottom: "16px" }}>
                                      <p style={{ margin: "0 0 8px 0", fontSize: "0.9rem", color: "var(--text-secondary)" }}><strong>User:</strong> {o.userId?.name} ({o.userId?.email})</p>
                                      <p style={{ margin: "0", fontSize: "0.9rem", color: "var(--text-secondary)" }}><strong>Contact:</strong> {o.contactDetails}</p>
                                  </div>
                                  <div style={{ display: "flex", gap: "10px" }}>
                                      <button onClick={() => handleApproveOwner(o._id, "approved")} className="btn-primary" style={{ padding: "8px", fontSize: "0.9rem", background: "var(--status-success)" }}>Approve</button>
                                      <button onClick={() => handleApproveOwner(o._id, "rejected")} className="btn-primary" style={{ padding: "8px", fontSize: "0.9rem", background: "var(--status-danger)" }}>Reject</button>
                                  </div>
                              </div>
                          ))
                      }
                  </div>

                  {/* Pending Lots Column */}
                  <div>
                      <h2 style={{ fontSize: "1.5rem", marginBottom: "16px", display: "flex", alignItems: "center", gap: "8px" }}>
                          <i className="fa-solid fa-square-parking" style={{ color: "var(--status-warning)" }}></i> Pending Parking Lots
                      </h2>
                      {pendingLots.length === 0 ? <p style={{ color: "var(--text-muted)" }}>No pending parking lot submissions.</p> : 
                          pendingLots.map(l => (
                              <div className="card" key={l._id} style={{ marginBottom: "16px" }}>
                                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "12px" }}>
                                      <h3 style={{ margin: 0 }}>{l.name}</h3>
                                  </div>
                                  <div style={{ flexGrow: 1, marginBottom: "16px" }}>
                                      <p style={{ margin: "0 0 8px 0", fontSize: "0.9rem", color: "var(--text-secondary)" }}><strong>Location:</strong> {l.location}, {l.district}</p>
                                      <p style={{ margin: "0 0 8px 0", fontSize: "0.9rem", color: "var(--text-secondary)" }}><strong>Owner:</strong> {l.ownerId?.name}</p>
                                      <p style={{ margin: "0", fontSize: "0.9rem", color: "var(--text-secondary)" }}><strong>Types:</strong> {l.vehicleTypes?.join(", ") || "Any"}</p>
                                  </div>
                                  <div style={{ display: "flex", gap: "10px" }}>
                                      <button onClick={() => handleApproveLot(l._id, "approved")} className="btn-primary" style={{ padding: "8px", fontSize: "0.9rem", background: "var(--status-success)" }}>Approve</button>
                                      <button onClick={() => handleApproveLot(l._id, "rejected")} className="btn-primary" style={{ padding: "8px", fontSize: "0.9rem", background: "var(--status-danger)" }}>Reject</button>
                                  </div>
                              </div>
                          ))
                      }
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

const StatCard = ({ title, value, icon, color }) => (
  <div style={{ background: "var(--bg-secondary)", padding: "24px", borderRadius: "var(--radius-lg)", boxShadow: "var(--shadow-md)", border: "1px solid var(--border-subtle)", position: "relative", overflow: "hidden", transition: "transform 0.2s ease", cursor: "default" }} onMouseOver={e => e.currentTarget.style.transform = "translateY(-5px)"} onMouseOut={e => e.currentTarget.style.transform = "translateY(0)"}>
    <div style={{ position: "absolute", right: "-10px", top: "-10px", opacity: 0.05, fontSize: "6rem", color: color }}>
        <i className={`fa-solid ${icon}`}></i>
    </div>
    <div style={{ color: "var(--text-secondary)", fontSize: "0.95rem", fontWeight: "600", textTransform: "uppercase", letterSpacing: "0.5px", marginBottom: "8px", display: "flex", alignItems: "center", gap: "8px" }}>
        <i className={`fa-solid ${icon}`} style={{ color: color }}></i> {title}
    </div>
    <div style={{ fontSize: "2.5rem", fontWeight: "800", color: "var(--text-primary)", letterSpacing: "-1px" }}>{value}</div>
  </div>
);

const thStyle = { padding: "16px 20px", color: "var(--text-secondary)", fontSize: "0.85rem", textTransform: "uppercase", fontWeight: "700", borderBottom: "2px solid var(--border-subtle)" };
const tdStyle = { padding: "16px 20px", color: "var(--text-primary)", borderBottom: "1px solid var(--border-subtle)", fontSize: "0.95rem" };
